ALTER TABLE profiles ADD COLUMN IF NOT EXISTS max_drive_limit DECIMAL DEFAULT 1000000; CREATE TABLE IF NOT EXISTS reviews (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), donor_id UUID REFERENCES profiles(id) ON DELETE CASCADE, ngo_id UUID REFERENCES profiles(id) ON DELETE CASCADE, rating INTEGER CHECK (rating >= 1 AND rating <= 5), comment TEXT, created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL);
